    @Test
    @DisplayName("TC02: load() sets one system property when systemProperties=true and one entry in .env (branch-true, loop-1)")
    void test_TC02() throws Exception {
        // branch-true: enable systemProperties, so loop body will set properties
        // loop-1: one line in .env
        Path dir = Files.createTempDirectory("env");
        Files.writeString(dir.resolve(".env"), "KEY=VALUE");
        DotenvBuilder builder = Dotenv.configure().directory(dir.toString()).systemProperties();

        try {
            Dotenv dotenv = builder.load();
            // system property should be set
            assertEquals("VALUE", System.getProperty("KEY"),
                         "System property KEY should be set to VALUE");
            // dotenv.get should also return the value from the file
            assertEquals("VALUE", dotenv.get("KEY"),
                         "dotenv.get should return VALUE for KEY");
        } finally {
            // clean up for isolation
            System.clearProperty("KEY");
        }
    }

    @Test
    @DisplayName("TC03: load() sets multiple system properties when systemProperties=true and multiple entries in .env (branch-true, loop-N)")
    void test_TC03() throws Exception {
        // branch-true: enable systemProperties
        // loop-N: multiple entries
        Path p = Files.createTempDirectory("env");
        Files.writeString(p.resolve(".env"), "A=1\nB=2\nC=3");
        DotenvBuilder builder = Dotenv.configure().directory(p.toString()).systemProperties();

        try {
            Dotenv dotenv = builder.load();
            // all three properties should be set
            assertEquals("1", System.getProperty("A"), "Property A should be set to 1");
            assertEquals("2", System.getProperty("B"), "Property B should be set to 2");
            assertEquals("3", System.getProperty("C"), "Property C should be set to 3");
            // and dotenv.get should reflect file values as well
            assertEquals("1", dotenv.get("A"));
            assertEquals("2", dotenv.get("B"));
            assertEquals("3", dotenv.get("C"));
        } finally {
            System.clearProperty("A");
            System.clearProperty("B");
            System.clearProperty("C");
